query:
{
  functionApps(
    where: {
      authSettings_SOME: {
        enabled: true
        OR: [
          { unauthenticatedClientAction: "AllowAnonymous" }
          { unauthenticatedClientAction: "" }
          { unauthenticatedClientAction: null }
        ]
      }
    }
  ) {
    ...AssetFragment
  }
}
